SELECT 
  (SELECT SUM(b.spent) FROM budget b JOIN event e ON b.link_to_event = e.event_id WHERE e.event_date LIKE '2019-%') -
  (SELECT SUM(b.spent) FROM budget b JOIN event e ON b.link_to_event = e.event_id WHERE e.event_date LIKE '2020-%') AS amount_difference;

SELECT MIN(milliseconds) AS fastest_lap_time
FROM lapTimes
WHERE milliseconds IS NOT NULL;
